// Approx. on-map centroid of each zone (in viewBox units) for label placement.
const ZONE_CENTROID: Record<string, { x: number; y: number }> = {
  NR: { x: 334.9, y: 228.4 },
  NER: { x: 846.4, y: 359.2 },
  WR: { x: 216.9, y: 473.5 },
  ER: { x: 519.2, y: 448.7 },
  SRTKKA: { x: 344.6, y: 705.6 },
  SRTN: { x: 380.9, y: 822.3 },
};

type Zone = { code: string; label: string; events: number; participants: number };

function zoneFill(events: number, maxEvents: number, isTop: boolean): string {
  if (isTop) return SAFFRON;
  const t = maxEvents > 0 ? events / maxEvents : 0;
  const opacity = 0.35 + 0.5 * t;
  return INK + Math.round(opacity * 255).toString(16).padStart(2, "0");
}

export function IndiaMap({ zones }: { zones: Zone[] }) {
  const known = zones.filter((z) => ZONE_GEO[z.code]);
  const maxEvents = Math.max(1, ...known.map((z) => z.events));
  const topCode =
    known.length > 0
      ? known.reduce((a, b) => (b.events > a.events ? b : a)).code
      : null;
  const byCode = new Map(known.map((z) => [z.code, z]));

  return (
    <section className="rounded-2xl border border-[#1a1a3e]/8 bg-white px-6 py-5">
      <div className="text-[11px] font-semibold uppercase tracking-[0.16em] text-[#FF9933]">
        Across India · activity by zone
      </div>

      <div className="mt-4 flex flex-col gap-6 lg:flex-row lg:items-start">
        {/* Map */}
        <div className="mx-auto w-full max-w-[460px] lg:mx-0 lg:flex-1">
          <svg
            viewBox={VIEW_BOX}
            role="img"
            aria-label="Map of India shaded by Yi zone activity"
            className="h-auto w-full"
          >
            {/* Neutral states (islands etc.) */}
            <path
              d={NEUTRAL_PATH}
              fill={INK}
              fillOpacity={0.06}
              stroke="#ffffff"
              strokeWidth={1}
            />

            {/* Zones */}
            {known.map((z) => {
              const isTop = z.code === topCode;
              return (
                <Link
                  key={z.code}
                  href={`/yip/dashboard/zones/${z.code.toLowerCase()}`}
                >
                  <g className="transition-opacity duration-150 hover:opacity-90">
                    <path
                      d={ZONE_GEO[z.code]}
                      fill={zoneFill(z.events, maxEvents, isTop)}
                      stroke="#ffffff"
                      strokeWidth={1.1}
                      strokeLinejoin="round"
                    />
                  </g>
                </Link>
              );
            })}

            {/* Zone labels */}
            {known.map((z) => {
              const c = ZONE_CENTROID[z.code];
              if (!c) return null;
              const isTop = z.code === topCode;
              return (
                <text
                  key={`lbl-${z.code}`}
                  x={c.x}
                  y={c.y}
                  textAnchor="middle"
                  className="pointer-events-none select-none"
                  fontSize={22}
                  fontWeight={700}
                  fill={isTop ? INK : "#ffffff"}
                  style={{ paintOrder: "stroke" }}
                  stroke={isTop ? "#ffffff" : "transparent"}
                  strokeWidth={isTop ? 3 : 0}
                >
                  {z.code}
                </text>
              );
            })}
          </svg>

          {/* Gradient legend */}
          <div className="mt-3 flex items-center gap-3 px-1">
            <span className="text-[10px] font-medium uppercase tracking-wide text-[#1a1a3e]/50">
              fewer events
            </span>
            <div
              className="h-2 flex-1 rounded-full"
              style={{
                background: `linear-gradient(90deg, ${INK}59 0%, ${INK}cc 70%, ${SAFFRON} 100%)`,
              }}
            />
            <span className="text-[10px] font-medium uppercase tracking-wide text-[#FF9933]">
              most active
            </span>
          </div>
        </div>

        {/* Legend / zone list */}
        <ul className="w-full shrink-0 space-y-1.5 lg:w-[280px]">
          {[...known]
            .sort((a, b) => b.events - a.events)
            .map((z) => {
              const isTop = z.code === topCode;
              return (
                <li key={z.code}>
                  <Link
                    href={`/yip/dashboard/zones/${z.code.toLowerCase()}`}
                    className="group flex items-center gap-3 rounded-xl border border-transparent px-3 py-2 transition-colors hover:border-[#1a1a3e]/10 hover:bg-[#1a1a3e]/[0.03]"
                  >
                    <span
                      className="mt-0.5 h-3.5 w-3.5 shrink-0 rounded-[4px] ring-1 ring-inset ring-black/5"
                      style={{
                        backgroundColor: zoneFill(z.events, maxEvents, isTop),
                      }}
                    />
                    <span className="min-w-0 flex-1">
                      <span className="block truncate text-[13px] font-semibold text-[#1a1a3e]">
                        {z.label}
                      </span>
                      <span className="block text-[12px] text-[#1a1a3e]/55">
                        {z.events} event{z.events === 1 ? "" : "s"} ·{" "}
                        {z.participants} student{z.participants === 1 ? "" : "s"}
                      </span>
                    </span>
                    {isTop && (
                      <span className="shrink-0 rounded-full bg-[#FF9933]/15 px-2 py-0.5 text-[10px] font-semibold uppercase tracking-wide text-[#b5670f]">
                        Most active
                      </span>
                    )}
                  </Link>
                </li>
              );
            })}
        </ul>
      </div>
    </section>
  );
}
